{
  "query_used": "healthcare apprenticeships challenges solutions",
  "total_found": 19,
  "results": [
    {
      "title": "Apprenticeship in Healthcare: Promising Models and Persistent Challenges",
      "authors": ["Spaulding, S.", "Mikelson, K."],
      "year": 2019,
      "source": "Urban Institute",
      "key_findings": "Healthcare apprenticeships face structural barriers including employer cost concerns, clinical rotation logistics, and licensing board constraints. Completion rates improve significantly (up to 55-60%) in programs with dedicated employer navigators and wraparound support services. However, these enhanced programs cost 40-60% more to operate."
    },
    {
      "title": "Why Healthcare Apprenticeships Fail: A Qualitative Study of Employer Dropout",
      "authors": ["Barnow, B.", "Spaulding, S."],
      "year": 2021,
      "source": "Georgetown Center on Education and the Workforce",
      "key_findings": "Primary reasons healthcare employers exit apprenticeship programs: administrative burden (cited by 71% of dropouts), difficulty coordinating clinical supervision with patient care demands (64%), and uncertainty about ROI given high completion failure rates (58%). Recommends sector-specific intermediaries and reduced reporting burden."
    },
    {
      "title": "When Apprenticeship Works: Lessons from High-Performing Healthcare Programs",
      "authors": ["Fein, D."],
      "year": 2023,
      "source": "Abt Associates",
      "key_findings": "Three high-performing healthcare apprenticeship programs (in WA, MN, and MA) achieved completion rates of 68-74% through state intermediary support, employer consortia, and integration with community college curricula. However, these programs cost $42,000-$56,000 per completer and required substantial state co-investment."
    },
    {
      "title": "Federal Apprenticeship Policy: Lessons from the ApprenticeshipUSA Grants",
      "authors": ["Eyster, L.", "Barnow, B."],
      "year": 2022,
      "source": "Urban Institute",
      "key_findings": "ApprenticeshipUSA grants produced highly variable outcomes. Healthcare grantees underperformed relative to construction and manufacturing grantees on completion and wage gain metrics. Recommends conditional funding tied to performance benchmarks, with hold-harmless provisions for sectors with structural barriers."
    },
    {
      "title": "Rethinking Non-Traditional Apprenticeship: A Framework for Sector-Contingent Investment",
      "authors": ["Carew, D.", "Spaulding, S."],
      "year": 2025,
      "source": "Brookings Institution Working Paper",
      "key_findings": "Proposes tiered federal investment model: Tier 1 (established sectors with strong evidence: construction, electrical, manufacturing) receive unconditional funding increases; Tier 2 (sectors with mixed evidence: IT, healthcare) receive conditional funding contingent on meeting intermediate performance benchmarks; Tier 3 (nascent sectors) receive pilot funding only. Authors argue this framework avoids both under-investment and evidence-free expansion."
    }
  ]
}

